import torch.nn as nn

# 1D CNN用于DNA序列motif检测
class DNA_CNN(nn.Module):
    def __init__(self):
        super().__init__()
        self.conv1 = nn.Conv1d(4, 64, kernel_size=12)  # 4=ATCG
        self.pool = nn.MaxPool1d(4)
        self.conv2 = nn.Conv1d(64, 128, 8)
        self.fc = nn.Linear(128, 1)  # 输出: 是否含有motif
    def forward(self, x):
        x = self.pool(torch.relu(self.conv1(x)))
        x = self.pool(torch.relu(self.conv2(x)))
        return self.fc(x.mean(dim=-1)).squeeze()

import torch.nn as nn

# 残差块: 深度学习能训练100+层的关键
class ResidualBlock(nn.Module):
    def __init__(self, dim):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(dim, dim), nn.ReLU(),
            nn.Linear(dim, dim)
        )
    def forward(self, x):
        return x + self.net(x)  # ← 跳跃连接！

from torch_geometric.nn import GCNConv
import torch.nn as nn

class MoleculeGNN(nn.Module):
    def __init__(self):
        super().__init__()
        self.conv1 = GCNConv(32, 64)  # 原子特征→64维
        self.conv2 = GCNConv(64, 64)
        self.fc = nn.Linear(64, 1)    # 输出: 毒性
    def forward(self, x, edge_index):
        x = torch.relu(self.conv1(x, edge_index))
        x = torch.relu(self.conv2(x, edge_index))
        return self.fc(x.mean(dim=0))

# Seq2Seq概念: 编码→压缩→解码
class Encoder(nn.Module):
    def __init__(self):
        self.rnn = nn.LSTM(64, 256)
    def forward(self, x):
        _, (h, c) = self.rnn(x)  # 最后时间步的隐藏状态=上下文向量
        return h, c

class Decoder(nn.Module):
    def __init__(self):
        self.rnn = nn.LSTM(64, 256)
        self.out = nn.Linear(256, 20)  # 20种氨基酸
    def forward(self, x, h, c):
        out, (h, c) = self.rnn(x, (h, c))
        return self.out(out), h, c

# Transformer的核心: 多头自注意力
class MultiHeadAttention(nn.Module):
    def __init__(self, d_model=512, n_heads=8):
        super().__init__()
        self.qkv = nn.Linear(d_model, 3*d_model)  # QKV一起算
        self.out = nn.Linear(d_model, d_model)
    def forward(self, x):
        B, T, C = x.shape
        qkv = self.qkv(x).reshape(B, T, 3, 8, C//8)
